param(
    [string]$Mensagem = 'Ja acabou o script. Pode continuar o atendimento e validar os proximos passos.',
    [ValidateSet('Sucesso','Pendencias')]
    [string]$Status = 'Sucesso'
)

Add-Type -AssemblyName PresentationFramework
Add-Type -AssemblyName PresentationCore
Add-Type -AssemblyName WindowsBase

# Caminho da imagem
$imagem = Join-Path $PSScriptRoot 'toasty.png'

# Verifica se a imagem existe
if (!(Test-Path $imagem)) {
    Write-Error "Imagem nao encontrada em: $imagem"
    exit
}

# Dimensoes da janela
$windowWidth = 150
$windowHeight = 150

# Posicao da janela no canto inferior direito
$screenWidth = [System.Windows.SystemParameters]::PrimaryScreenWidth
$screenHeight = [System.Windows.SystemParameters]::PrimaryScreenHeight
$posX = $screenWidth - $windowWidth - 10
$posY = $screenHeight - $windowHeight - 50

# Cria e exibe a janela em thread STA com ShowDialog (bloqueante e confiavel)
$job = {
    param ($img, $w, $h, $x, $y)

    Add-Type -AssemblyName PresentationFramework

    $window = New-Object System.Windows.Window
    $window.Width = $w
    $window.Height = $h
    $window.WindowStyle = 'None'
    $window.AllowsTransparency = $true
    $window.Background = 'Transparent'
    $window.Topmost = $true
    $window.ShowInTaskbar = $false
    $window.Left = $x
    $window.Top = $y

    $image = New-Object System.Windows.Controls.Image
    $image.Source = [System.Windows.Media.Imaging.BitmapImage]::new((New-Object Uri($img)))
    $image.Stretch = 'Uniform'

    $grid = New-Object System.Windows.Controls.Grid
    $grid.Children.Add($image)
    $window.Content = $grid

    # Timer para fechar a janela
    $timer = New-Object System.Windows.Threading.DispatcherTimer
    $timer.Interval = [TimeSpan]::FromSeconds(3)
    $timer.Add_Tick({
        $timer.Stop()
        $window.Close()
    })
    $timer.Start()

    $window.ShowDialog() | Out-Null
}

# Inicia nova thread STA com argumento
$ps = [powershell]::Create()
$ps.AddScript($job).AddArgument($imagem).AddArgument($windowWidth).AddArgument($windowHeight).AddArgument($posX).AddArgument($posY)

$runspace = [runspacefactory]::CreateRunspace()
$runspace.ApartmentState = "STA"
$runspace.Open()
$ps.Runspace = $runspace
$ps.BeginInvoke() | Out-Null



$base64 = @'

'@

$caminhoTemp = "$env:TEMP\shutdown_xp.wav"
[IO.File]::WriteAllBytes($caminhoTemp, [Convert]::FromBase64String($base64))

try {
    $som = New-Object System.Media.SoundPlayer
    $som.SoundLocation = $caminhoTemp
    $som.Load()
    $som.PlaySync()
} catch {
    Write-Warning "Erro ao tentar tocar o som: $_"
}

Remove-Item $caminhoTemp -ErrorAction SilentlyContinue

# Mostrar Sonic impaciente no centro da tela por 15 segundos
Add-Type -AssemblyName PresentationFramework

$videoPath = Join-Path $PSScriptRoot 'sonic.mp4'

if (!(Test-Path $videoPath)) {
    Write-Warning "Video nao encontrado em: $videoPath"
    return
}

# Criacao da janela
$window = New-Object System.Windows.Window
$window.Width = 500
$window.Height = 600
$window.WindowStartupLocation = 'CenterScreen'
$window.WindowStyle = 'None'
$window.Topmost = $true
$window.AllowsTransparency = $true
$window.Background = 'Transparent'
$window.ShowInTaskbar = $false

# Grid principal com duas linhas (video + texto)
$grid = New-Object System.Windows.Controls.Grid
$grid.RowDefinitions.Add((New-Object System.Windows.Controls.RowDefinition))
$grid.RowDefinitions.Add((New-Object System.Windows.Controls.RowDefinition))

# Elemento de video com loop manual
$media = New-Object System.Windows.Controls.MediaElement
$media.Source = $videoPath
$media.LoadedBehavior = 'Manual'
$media.UnloadedBehavior = 'Stop'
$media.Stretch = 'Uniform'
$media.HorizontalAlignment = 'Center'
$media.VerticalAlignment = 'Top'

# Loop manual do video
$media.Add_MediaEnded({
    $media.Position = [TimeSpan]::Zero
    $media.Play()
})

# Iniciar a reproducao manualmente
$media.Play()

# Adiciona video na primeira linha
[System.Windows.Controls.Grid]::SetRow($media, 0)
$grid.Children.Add($media)

# Texto provocativo piscando e mudando de cor
$texto = New-Object System.Windows.Controls.TextBlock
$texto.Text = $Mensagem
$texto.FontSize = 20
$texto.TextWrapping = 'Wrap'
$texto.HorizontalAlignment = 'Center'
$texto.VerticalAlignment = 'Center'
$texto.Margin = '10'

Add-Type -AssemblyName PresentationCore
$opacityAnim = New-Object System.Windows.Media.Animation.DoubleAnimation
$opacityAnim.From = 1.0
$opacityAnim.To = 0.2
$opacityAnim.Duration = New-Object System.Windows.Duration([TimeSpan]::FromSeconds(0.6))
$opacityAnim.AutoReverse = $true
$opacityAnim.RepeatBehavior = [System.Windows.Media.Animation.RepeatBehavior]::Forever

$colorAnim = New-Object System.Windows.Media.Animation.ColorAnimation
$colorAnim.From = [System.Windows.Media.Colors]::White
$colorAnim.To = [System.Windows.Media.Colors]::Red
$colorAnim.Duration = New-Object System.Windows.Duration([TimeSpan]::FromSeconds(1))
$colorAnim.AutoReverse = $true
$colorAnim.RepeatBehavior = [System.Windows.Media.Animation.RepeatBehavior]::Forever

$solidColor = [System.Windows.Media.Colors]::White
$brush = New-Object System.Windows.Media.SolidColorBrush($solidColor)
$brush.BeginAnimation([System.Windows.Media.SolidColorBrush]::ColorProperty, $colorAnim)
$texto.Foreground = $brush
$texto.BeginAnimation([System.Windows.UIElement]::OpacityProperty, $opacityAnim)

# Adiciona texto na segunda linha
[System.Windows.Controls.Grid]::SetRow($texto, 1)
$grid.Children.Add($texto)

$window.Content = $grid

# Timer para fechar apos 30 segundos
$timer = New-Object System.Windows.Threading.DispatcherTimer
$timer.Interval = [TimeSpan]::FromSeconds(30)
$timer.Add_Tick({ $timer.Stop(); $window.Close() })
$timer.Start()

# Exibir a janela
$window.ShowDialog() | Out-Null